import React from "react";
import { Outlet, Link, useLocation } from "react-router-dom";

const AdminLayout = () => {
  const location = useLocation();

  const navItems = [
    { name: "Tổng quan", path: "/admin/dashboard", icon: "📊" },
    { name: "Quản lý sản phẩm", path: "/admin/products", icon: "🛍️" },
    { name: "Quản lý đơn hàng", path: "/admin/orders", icon: "📦" },
    { name: "Quản lý danh mục", path: "/admin/categories", icon: "🗂️" },
    { name: "Quản lý người dùng", path: "/admin/users", icon: "👤" },
  ];

  const currentPage = location.pathname.replace("/admin/", "").toUpperCase();

  return (
    <div className="flex min-h-screen bg-gray-100 font-sans">
      {/* Sidebar */}
      <aside className="w-64 bg-gradient-to-b from-green-50 to-white border-r border-gray-200 p-5 flex flex-col">
        {/* Profile */}
        <div className="flex items-center mb-6">
          <div className="w-12 h-12 rounded-full bg-green-200 flex items-center justify-center text-white font-bold">
            A
          </div>
          <div className="ml-3">
            <p className="text-sm font-semibold text-gray-700">Admin</p>
            <p className="text-xs text-gray-400">DTP Flower Shop</p>
          </div>
        </div>

        {/* Navigation */}
        <nav className="flex flex-col gap-2">
          {navItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all duration-200 ${
                location.pathname === item.path
                  ? "bg-green-200 text-green-800 font-semibold shadow"
                  : "text-gray-600 hover:bg-green-50 hover:text-green-700"
              }`}
            >
              <span>{item.icon}</span>
              {item.name}
            </Link>
          ))}

          <a
            href="/"
            className="mt-4 text-sm text-blue-500 hover:underline"
            target="_blank"
            rel="noreferrer"
          >
            Xem trang web
          </a>
        </nav>
      </aside>

      {/* Content */}
      <main className="flex-1 p-6 overflow-y-auto">
        {/* Header */}
        <div className="flex justify-between items-center mb-6">
          <h1 className="text-2xl font-semibold text-gray-700">
            {currentPage || "Dashboard"}
          </h1>
        </div>

        {/* Page content card */}
        <div className="bg-white p-6 rounded-2xl shadow-md min-h-[70vh]">
          <Outlet />
        </div>
      </main>
    </div>
  );
};

export default AdminLayout;
